    padding: 1rem;
    transition: all 0.2s;
    border: 1px solid #dee2e6;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    margin-bottom: 0.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid currentColor;
    opacity: 0.3;
}

.preview-row {
    display: flex;
    gap: 0.5rem;
    align-items: center;
    margin-bottom: 0.5rem;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    background: #0d6efd;
    color: white;
}

.preview-meta {
    font-size: 0.8rem;
    opacity: 0.6;
    margin: 0;
}

/* ── Toast ───────────────────────────────────────────── */
.toast-message {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    margin-bottom: 1rem;
    font-size: 0.9rem;
    animation: slide-in 0.25s ease-out;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

.toast-dismiss {
    border: none;
    background: transparent;
    font-size: 1.2rem;
    cursor: pointer;
    color: inherit;
    padding: 0 0.25rem;
    line-height: 1;
}

@keyframes slide-in {
    from {
        opacity: 0;
        transform: translateY(-0.5rem);
    }
    to {
