{"file_text": "@page "/settings"
@using sv_467c42e7d5c740d1802a7cc2106188d9.Models
@using sv_467c42e7d5c740d1802a7cc2106188d9.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar" aria-label="Settings sections">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)"
                    aria-current="@(section == _activeSection ? "page" : null)">
                <span class="sidebar-icon">@GetSectionIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")" role="alert">
                @_toastMessage
                <button class="toast-dismiss" @onclick="DismissToast" aria-label="Dismiss">×</button>
            </div>
        }

        @switch (_activeSection)
        {
            case "Profile":
                @RenderProfileSection()
                break;
            case "Notifications":
                @RenderNotificationsSection()
                break;
            case "Security":
                @RenderSecuritySection()
                break;
            case "Appearance":
                @RenderAppearanceSection()
                break;
        }
    </div>
</div>

<!-- Revoke Session Confirmation Dialog -->
@if (_showRevokeDialog)
{
    <div class="modal-backdrop" @onclick="CancelRevoke">
        <div class="modal-dialog" @onclick:stopPropagation="true" role="dialog" aria-labelledby="revokeDialogTitle">
            <h5 id="revokeDialogTitle">Revoke Session</h5>
            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?</p>
            <p class="text-muted">This will sign out that device immediately.</p>
            <div class="modal-actions">
                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
            </div>
        </div>
    </div>
}

@code {
    // ── Section navigation ──────────────────────────────────
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    // ── Toast ───────────────────────────────────────────────
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile ─────────────────────────────────────────────
    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // ── Notifications ───────────────────────────────────────
    private NotificationPrefs? _notifPrefs;
    private bool _editEmailNotif;
    private bool _editPushNotif;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = [];

    // ── Security ────────────────────────────────────────────
    private SecuritySettings? _security;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance ──────────────────────────────────────────
    private AppearanceSettings? _appearance;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    private static readonly string[] AvailableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    // ── Lifecycle ───────────────────────────────────────────
    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
        await LoadNotificationsAsync();
        await LoadSecurityAsync();
        await LoadAppearanceAsync();
    }

    // ── Navigation ──────────────────────────────────────────
    private void SetActiveSection(string section)
    {
        _activeSection = section;
        DismissToast();
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    // ── Toast helpers ───────────────────────────────────────
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, _toastCts.Token);
            DismissToast();
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    private void DismissToast()
    {
        _toastMessage = null;
        _toastCts?.Cancel();
    }

    // ═══════════════════════════════════════════════════════
    //  PROFILE
    // ═══════════════════════════════════════════════════════
    private async Task LoadProfileAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        _savedProfile = _profile;
        ApplyProfileToEdit(_profile);
    }

    private void ApplyProfileToEdit(UserProfile p)
    {
        _editDisplayName = p.DisplayName;
        _editEmail = p.Email;
        _editBio = p.Bio;
        _editAvatarUrl = p.AvatarUrl;
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _savedProfile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            ApplyProfileToEdit(_savedProfile);
    }

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section>
            <h3>Profile</h3>
            <p class="section-subtitle">Manage your public profile information.</p>

            <div class="settings-card">
                <div class="avatar-area">
                    <div class="avatar-preview">
                        <img src="@_editAvatarUrl" alt="Avatar preview" onerror="this.style.display='none'" />
                    </div>
                    <div class="form-group">
                        <label for="avatarUrl">Avatar URL</label>
                        <input id="avatarUrl" type="url" class="form-control" @bind="_editAvatarUrl" placeholder="https://..." />
                    </div>
                </div>

                <div class="form-group">
                    <label for="displayName">Display Name</label>
                    <input id="displayName" type="text" class="form-control" @bind="_editDisplayName" />
                </div>

                <div class="form-group">
                    <label for="email">Email</label>
                    <input id="email" type="email" class="form-control" @bind="_editEmail" />
                </div>

                <div class="form-group">
                    <label for="bio">Bio</label>
                    <textarea id="bio" class="form-control" rows="4" @bind="_editBio"></textarea>
                </div>

                <div class="button-row">
                    <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
                </div>
            </div>
        </section>
    };

    // ═══════════════════════════════════════════════════════
    //  NOTIFICATIONS
    // ═══════════════════════════════════════════════════════
    private async Task LoadNotificationsAsync()
    {
        _notifPrefs = await SettingsService.GetNotificationPrefsAsync();
        _editEmailNotif = _notifPrefs.EmailNotifications;
        _editPushNotif = _notifPrefs.PushNotifications;
        _editWeeklyDigest = _notifPrefs.WeeklyDigest;
        _editMutedChannels = [.. _notifPrefs.MutedChannels];
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted) _editMutedChannels.Add(channel);
        else _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var updated = new NotificationPrefs(_editEmailNotif, _editPushNotif, _editWeeklyDigest, [.. _editMutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notifPrefs = updated;
        await ShowToast("Notification preferences saved!");
    }

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section>
            <h3>Notifications</h3>
            <p class="section-subtitle">Choose how you want to be notified.</p>

            <div class="settings-card">
                <h6>General</h6>

                <div class="toggle-row">
                    <label class="toggle-label" for="emailNotif">Email Notifications</label>
                    <label class="switch">
                        <input id="emailNotif" type="checkbox" @bind="_editEmailNotif" />
                        <span class="slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <label class="toggle-label" for="pushNotif">Push Notifications</label>
                    <label class="switch">
                        <input id="pushNotif" type="checkbox" @bind="_editPushNotif" />
                        <span class="slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <label class="toggle-label" for="weeklyDigest">Weekly Digest</label>
                    <label class="switch">
                        <input id="weeklyDigest" type="checkbox" @bind="_editWeeklyDigest" />
                        <span class="slider"></span>
                    </label>
                </div>
            </div>

            <div class="settings-card">
                <h6>Muted Channels</h6>
                <p class="text-muted">Select channels you want to mute.</p>

                @foreach (var channel in SettingsService.AllChannels)
                {
                    var isMuted = _editMutedChannels.Contains(channel);
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }

                <div class="button-row mt-3">
                    <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
                </div>
            </div>
        </section>
    };

    // ═══════════════════════════════════════════════════════
    //  SECURITY
    // ═══════════════════════════════════════════════════════
    private async Task LoadSecurityAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword) ||
            string.IsNullOrWhiteSpace(_confirmPassword))
        {
            await ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", isError: true);
            return;
        }

        if (_newPassword.Length < 8)
        {
            await ShowToast("Password must be at least 8 characters.", isError: true);
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private async Task Toggle2FA()
    {
        if (_security is null) return;
        // In a real app this would trigger an enrollment flow
        var updated = _security with { TwoFactorEnabled = !_security.TwoFactorEnabled };
        _security = updated;
        var status = updated.TwoFactorEnabled ? "enabled" : "disabled";
        await ShowToast($"Two-factor authentication {status}.");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
            await ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatTimeAgo(DateTime dt)
    {
        var span = DateTime.UtcNow - dt;
        if (span.TotalMinutes < 1) return "just now";
        if (span.TotalMinutes < 60) return $"{(int)span.TotalMinutes}m ago";
        if (span.TotalHours < 24) return $"{(int)span.TotalHours}h ago";
        return $"{(int)span.TotalDays}d ago";
    }

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section>
            <h3>Security</h3>
            <p class="section-subtitle">Manage your account security settings.</p>

            <!-- Change Password -->
            <div class="settings-card">
                <button class="expand-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    <span>🔑 Change Password</span>
                    <span class="expand-chevron @(_changePasswordExpanded ? "expanded" : "")">▶</span>
                </button>

                @if (_changePasswordExpanded)
                {
                    <div class="expand-body">
                        <div class="form-group">
                            <label for="currentPw">Current Password</label>
                            <input id="currentPw" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPw">New Password</label>
                            <input id="newPw" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPw">Confirm New Password</label>
                            <input id="confirmPw" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>

                        @if (_security?.LastPasswordChange is not null)
                        {
                            <p class="text-muted mt-2">
                                Last changed: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                            </p>
                        }
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="settings-card">
                <div class="toggle-row">
                    <div>
                        <span class="toggle-label">Two-Factor Authentication</span>
                        <span class="status-badge @(_security?.TwoFactorEnabled == true ? "status-on" : "status-off")">
                            @(_security?.TwoFactorEnabled == true ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <label class="switch">
                        <input type="checkbox" checked="@(_security?.TwoFactorEnabled ?? false)" @onchange="async _ => await Toggle2FA()" />
                        <span class="slider"></span>
                    </label>
                </div>
            </div>

            <!-- Active Sessions -->
            <div class="settings-card">
                <h6>Active Sessions</h6>

                @if (_security?.Sessions is { Count: > 0 })
                {
                    <div class="table-responsive">
                        <table class="table table-sm">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th></th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var (session, idx) in _security.Sessions.Select((s, i) => (s, i)))
                                {
                                    var isCurrentSession = idx == 0;
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrentSession)
                                            {
                                                <span class="badge bg-success ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@FormatTimeAgo(session.LastActive)</td>
                                        <td>
                                            @if (!isCurrentSession)
                                            {
                                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RequestRevoke(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
                else
                {
                    <p class="text-muted">No active sessions.</p>
                }
            </div>
        </section>
    };

    // ═══════════════════════════════════════════════════════
    //  APPEARANCE
    // ═══════════════════════════════════════════════════════
    private async Task LoadAppearanceAsync()
    {
        _appearance = await SettingsService.GetAppearanceAsync();
        _editTheme = _appearance.Theme;
        _editFontSize = _appearance.FontSize;
        _editLanguage = _appearance.Language;
        _editCompactMode = _appearance.CompactMode;
    }

    private async Task SaveAppearance()
    {
        var updated = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearance = updated;
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _editFontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section>
            <h3>Appearance</h3>
            <p class="section-subtitle">Customize how the application looks.</p>

            <div class="settings-card">
                <h6>Theme</h6>
                <div class="radio-group">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <label class="radio-option">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_editTheme == theme)"
                                   @onchange="() => _editTheme = theme" />
                            <span class="radio-label">@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="settings-card">
                <h6>Font Size</h6>
                <div class="radio-group">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <label class="radio-option">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_editFontSize == size)"
                                   @onchange="() => _editFontSize = size" />
                            <span class="radio-label">@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="settings-card">
                <h6>Language</h6>
                <select class="form-select" @bind="_editLanguage">
                    @foreach (var lang in AvailableLanguages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="settings-card">
                <div class="toggle-row">
                    <label class="toggle-label" for="compactMode">Compact Mode</label>
                    <label class="switch">
                        <input id="compactMode" type="checkbox" @bind="_editCompactMode" />
                        <span class="slider"></span>
                    </label>
                </div>
            </div>

            <!-- Live Preview -->
            <div class="settings-card">
                <h6>Preview</h6>
                <div class="appearance-preview @(_editTheme == "Dark" ? "preview-dark" : "preview-light")"
                     style="font-size: @PreviewFontSize; @(_editCompactMode ? "padding: 0.5rem; line-height: 1.2;" : "")">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <p>This is a preview of your selected appearance settings.</p>
                    <div class="preview-row">
                        <span class="preview-badge">Badge</span>
                        <button class="btn btn-sm btn-primary" disabled>Button</button>
                    </div>
                    <p class="preview-meta">
                        Theme: @_editTheme · Font: @_editFontSize · Lang: @_editLanguage · Compact: @(_editCompactMode ? "On" : "Off")
                    </p>
                </div>
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };
}
