    padding: 1rem 0;
    border: 1px solid #e9ecef;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    width: 100%;
    padding: 0.6rem 1.25rem;
    border: none;
    background: transparent;
    color: #495057;
    font-size: 0.95rem;
    cursor: pointer;
    text-align: left;
    transition: background 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #212529;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
    width: 1.4rem;
    text-align: center;
}

/* ── Content ─────────────────────────────────────────── */
.settings-content {
    flex: 1;
    min-width: 0;
    max-width: 720px;
    position: relative;
}

.settings-content h3 {
    margin: 0 0 0.25rem;
    font-weight: 600;
}

.section-subtitle {
    color: #6c757d;
    margin-bottom: 1.25rem;
}

/* ── Card ────────────────────────────────────────────── */
.settings-card {
    background: #fff;
    border: 1px solid #e9ecef;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
}

.settings-card h6 {
    margin: 0 0 0.75rem;
    font-weight: 600;
}

/* ── Form elements ───────────────────────────────────── */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
}

.button-row {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
}

/* ── Avatar ──────────────────────────────────────────── */
.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.25rem;
    margin-bottom: 1rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #dee2e6;
    overflow: hidden;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-area .form-group {
    flex: 1;
}

/* ── Toggle switch ───────────────────────────────────── */
.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.4rem 0;
}

.toggle-label {
    font-weight: 500;
    font-size: 0.95rem;
}

.switch {
    position: relative;
    display: inline-block;
    width: 44px;
    height: 24px;
    flex-shrink: 0;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background: #ccc;
    border-radius: 24px;
    transition: background 0.2s;
}

.slider::before {
    content: "";
    position: absolute;
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background: white;
    border-radius: 50%;
    transition: transform 0.2s;
}

.switch input:checked + .slider {
    background: #0d6efd;
}

.switch input:checked + .slider::before {
    transform: translateX(20px);
}

/* ── Status badge ────────────────────────────────────── */
.status-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    margin-left: 0.5rem;
    font-weight: 500;
}

.status-on {
    background: #d1e7dd;
    color: #0f5132;
}

.status-off {
    background: #f8d7da;
    color: #842029;
}

/* ── Expandable panel ────────────────────────────────── */
.expand-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    border: none;
    background: transparent;
    padding: 0;
    font-size: 1rem;
    font-weight: 500;
    cursor: pointer;
    color: #212529;
}

.expand-chevron {
    font-size: 0.7rem;
    transition: transform 0.2s;
    color: #6c757d;
}

.expand-chevron.expanded {
    transform: rotate(90deg);
}

.expand-body {
    margin-top: 1rem;
    padding-top: 1rem;
    border-top: 1px solid #e9ecef;
}

/* ── Radio group ─────────────────────────────────────── */
.radio-group {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    padding: 0.4rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    transition: border-color 0.15s, background 0.15s;
}

.radio-option:has(input:checked) {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.radio-option input {
    accent-color: #0d6efd;
}

.radio-label {
    font-size: 0.9rem;
}

/* ── Appearance preview ──────────────────────────────── */
.appearance-preview {
    border-radius: 0.375rem;
    padding: 1rem;
    transition: all 0.2s;
    border: 1px solid #dee2e6;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-header {
    margin-bottom: 0.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid currentColor;
    opacity: 0.3;
}

.preview-row {
    display: flex;
    gap: 0.5rem;
    align-items: center;
    margin-bottom: 0.5rem;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    background: #0d6efd;
    color: white;
}

.preview-meta {
    font-size: 0.8rem;
    opacity: 0.6;
    margin: 0;
}

/* ── Toast ───────────────────────────────────────────── */
.toast-message {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    margin-bottom: 1rem;
    font-size: 0.9rem;
    animation: slide-in 0.25s ease-out;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

.toast-dismiss {
    border: none;
    background: transparent;
    font-size: 1.2rem;
    cursor: pointer;
    color: inherit;
    padding: 0 0.25rem;
    line-height: 1;
}

@keyframes slide-in {
    from {
        opacity: 0;
        transform: translateY(-0.5rem);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* ── Modal / Dialog ──────────────────────────────────── */
.modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.45);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.modal-dialog {
    background: #fff;
    border-radius: 0.5rem;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.15);
}

.modal-dialog h5 {
    margin: 0 0 0.75rem;
}

.modal-actions {
    display: flex;
    gap: 0.5rem;
    justify-content: flex-end;
    margin-top: 1rem;
}

/* ── Table tweaks ────────────────────────────────────── */
.table th {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.03em;
    color: #6c757d;
    font-weight: 600;
}

/* ── Responsive ──────────────────────────────────────── */
@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        display: flex;
        flex-wrap: wrap;
        padding: 0.5rem;
        position: static;
        gap: 0.25rem;
    }

    .sidebar-title {
        width: 100%;
        padding: 0.25rem 0.5rem;
    }

    .sidebar-item {
        padding: 0.5rem 0.75rem;
        border-radius: 0.375rem;
        width: auto;
    }

    .settings-content {
        max-width: 100%;
    }
}
